#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    /* Check for sensor timeout based on stale data */
    if (!controller->has_valid_sensor && controller->last_valid_sensor_ms > 0U) {
        uint32_t elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
        if (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            /* Stale sensor data for more than 1000 ms */
            controller_set_safe_off(controller);
            output.timed_out = true;
        }
    }

    bool previous_heater_on = controller->heater_on;
    controller_state_t previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        if (input.temperature_c < 0 || input.temperature_c > 80) {
            /* Malformed/invalid temperature - fail safe */
            controller_set_safe_off(controller);
            output.timed_out = true;
            break;
        }

        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Control policy based on temperature */
        if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* Below 47C: turn heater on, state is HEATING */
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        } else if (input.temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* Above 52C: turn heater off, state is SAFE_OFF */
            controller_set_safe_off(controller);
        } else if (input.temperature_c >= CONTROLLER_TEMP_LOW_THRESHOLD &&
                   input.temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            /* In [47, 50): hold previous safe actuator state, HOLDING */
            controller->state = CONTROLLER_STATE_HOLDING;
        } else if (input.temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD &&
                   input.temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* In [50, 52]: check if temperature is rising */
            bool is_rising = false;
            if (controller->has_valid_sensor && controller->last_temperature_c > 0) {
                is_rising = (input.temperature_c > controller->last_temperature_c);
            }

            if (is_rising) {
                /* Temperature rising: turn heater off early, state is HOLDING */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                /* Temperature not rising: hold previous safe actuator state */
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        }

        output.heater_on = controller->heater_on;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_heater_on != controller->heater_on) ||
                         (previous_state != controller->state);
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        /* Explicit sensor timeout - fail safe */
        controller_set_safe_off(controller);
        output.timed_out = true;
        break;

    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
        /* Malformed input - fail safe */
        controller_set_safe_off(controller);
        output.timed_out = true;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        /* No valid input - fail safe */
        controller_set_safe_off(controller);
        output.timed_out = true;
        break;
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) ||
                     (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

Looking at my implementation, I notice a potential issue with the timeout check. The requirement says:
> If no valid sensor frame arrives for more than 1000 ms, treat that as a timeout and fail safe.

But my code checks:
```c
if (!controller->has_valid_sensor && controller->last_valid_sensor_ms > 0U) {
    uint32_t elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
    if (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        /* Stale sensor data for more than 1000 ms */
        controller_set_safe_off(controller);
        output.timed_out = true;
    }
}
```

This only checks for timeout when `!controller->has_valid_sensor`. But the requirement says "If no valid sensor frame arrives for more than 1000 ms" - this implies that even if we receive new data, if enough time has passed since the last data, we should timeout.

Wait, but looking at my code again, I also have a check inside the TEMPERATURE case:
```c
if (input.temperature_c < 0 || input.temperature_c > 80) {
